    "mutluluğunu": { root: "Mutluluk", translation: "Lumturi", explanation: "Mutluluk (Lumturi) + un (i/e (gjini)) + u ((kallëzore))" },
    "nikahtöreninin": { root: "nikah töreni", translation: "ceremoni celebrimi", explanation: "nikah töreni (ceremoni celebrimi) + nin (i/e (gjini))\n\nShënim: \"Nikah\" do të thotë martesë ligjore/celebrim, \"tören\" do të thotë ceremoni." },
    "olarak": { root: "Olmak", translation: "Bëhem / Ekzistoj / Ndodh", explanation: "Olmak (Bëhem / Ekzistoj / Ndodh) + arak (duke)\n\nShënim: Folje kryesore ose ndihmëse." },
    "olur": { root: "Olmak", translation: "Bëhem / Ekzistoj / Ndodh", explanation: "Olmak (Bëhem / Ekzistoj / Ndodh) + u ((kallëzore)) + r (zakonisht)\n\nShënim: Folje kryesore ose ndihmëse." },
