    "yaşanır": { root: "Yaşamak", translation: "Jetoj", explanation: "Yaşamak (Jetoj) + an (që) + ı ((kallëzore)) + r (zakonisht)" },
    "yaşatılmasını": { root: "Yaşamak", translation: "Jetoj", explanation: "Yaşamak (Jetoj) + t (të shkuar) + ıl (pësore) + m (imi / ime) + a (drejt / te) + sın (ti je / je) + ı ((kallëzore))" },
