    "aşklar": { root: "Aşk", translation: "Dashuri (shumës)", explanation: "Aşk (Dashuri) + lar (shumës)\n\nShënim: Ndjenjë e fortë dashurie." },
    "aştığımızı": { root: "aşmak", translation: "kapërcej / kaloj (në të shkuarën)", explanation: "aşmak (kapërcej / kaloj) + tığ (që ka) + ı ((kallëzore)) + mız (ynë / jona) + ı ((kallëzore))\n\nShënim: Rrënja: aş. Përdoret për kalimin e maleve, pengesave ose kapërcimin e kufijve." },
    "başarılar": { root: "Başarı", translation: "Sukses (shumës)", explanation: "Başarı (Sukses) + lar (shumës)" },
