    "dediğimiz": { root: "Demek", translation: "thuash / them / do të thotë (në të shkuarën)", explanation: "Demek (Të thuash / them / do të thotë) + diğ (që ka) + i ((kallëzore)) + miz (ynë / jona)\n\nShënim: Shprehje ose kuptim i një fjale." },
    "deneyimlerimizden": { root: "deneyim", translation: "përvojë / eksperienca", explanation: "deneyim (përvojë / eksperiencë) + ler (shumës) + i ((kallëzore)) + miz (ynë / jona) + den (prej / nga)\n\nShënim: Nga folja \"denemek\" (provoj)." },
