    "günümüze": { root: "Gün", translation: "Ditë", explanation: "Gün (Ditë) + ü ((kallëzore)) + müz (ynë / jona) + e (drejt / te)" },
    "hatalardan": { root: "Hata", translation: "në / tek Gabim (shumës)", explanation: "Hata (Gabim) + lar (shumës) + dan (prej / nga)\n\nShënim: Gabim i bërë pa qëllim." },
    "hatırlanacaktır": { root: "hatırlanmak", translation: "do të kujtohet", explanation: "hatırlanmak (kujtohet) + acak (do të) + tır (është)\n\nShënim: Forma pasive e foljes \"hatırlamak\" (kujtoj)." },
    "hayallerimizin": { root: "Hayal", translation: "Ëndërr / Imagjinata", explanation: "Hayal (Ëndërr / Imagjinatë) + ler (shumës) + i ((kallëzore)) + miz (ynë / jona) + in (i/e (gjini))\n\nShënim: Ëndërr ose diçka e imagjinuar." },
    "hayatları": { root: "hayat", translation: "jeta", explanation: "hayat (jetë) + lar (shumës) + ı ((kallëzore))\n\nShënim: Huazim ballkanik i përdorur gjerësisht (Hajat)." },
    "hayatı": { root: "hayat", translation: "jetë", explanation: "hayat (jetë) + ı ((kallëzore))\n\nShënim: Huazim ballkanik i përdorur gjerësisht (Hajat)." },
