    "karşılaşan": { root: "Karşılaşmak", translation: "Përballem / Ndeshem / Takohem", explanation: "Karşılaşmak (Përballem / Ndeshem / Takohem) + an (që)\n\nShënim: Takohem me dikë ose ndeshem me një problem." },
    "karşılaştığımız": { root: "Karşılaşmak", translation: "Përballem / Ndeshem / Takohem (në të shkuarën)", explanation: "Karşılaşmak (Përballem / Ndeshem / Takohem) + tığ (që ka) + ı ((kallëzore)) + mız (ynë / jona)\n\nShënim: Takohem me dikë ose ndeshem me një problem." },
