    "olan": { root: "Olmak", translation: "Bëhem / Ekzistoj / Ndodh", explanation: "Olmak (Bëhem / Ekzistoj / Ndodh) + an (që)\n\nShënim: Folje kryesore ose ndihmëse." },
    "olursak": { root: "Olmak", translation: "Bëhem / Ekzistoj / Ndodh", explanation: "Olmak (Bëhem / Ekzistoj / Ndodh) + u ((kallëzore)) + r (zakonisht) + sak (nëse ne)\n\nShënim: Folje kryesore ose ndihmëse." },
    "oluşturur": { root: "Oluşturmak", translation: "krijosh / krijoj / formoj", explanation: "Oluşturmak (Të krijosh / krijoj / formoj) + u ((kallëzore)) + r (zakonisht)\n\nShënim: Bashkimi i pjesëve për të krijuar një të tërë." },
